// 1) Valida se custom_fields existe e possui ao menos 3 itens
if (
  !items[0].json.custom_fields ||
  !Array.isArray(items[0].json.custom_fields) ||
  items[0].json.custom_fields.length < 3
) {
  throw new Error("O array custom_fields não existe ou possui menos de 3 itens.");
}

const campo = items[0].json.custom_fields[2];

// 2) Garante que o campo possui options configuradas em type_config
const options = campo.type_config?.options;
if (!options || !Array.isArray(options)) {
  throw new Error("O campo não possui opções configuradas em type_config.options");
}

// 3) Encontra a opção cujo orderindex corresponde ao valor selecionado
const selecionada = options.find(opt => opt.orderindex === campo.value);
if (!selecionada) {
  throw new Error(`Nenhuma opção encontrada para o valor ${campo.value}`);
}

// 4) Utiliza regex para capturar o conteúdo dentro dos colchetes
const regex = /\[([^\]]+)\]/;
const match = selecionada.name.match(regex);
const tag = match ? match[1] : "";

// 5) Retorna os valores extraídos
return [
  {
    json: {
      customFieldValue: campo.value,
      customFieldName: selecionada.name,
      tag: tag
    }
  }
];

